// hard_a_expense_outliers
// Two-pass over a TOON array: pass 1 computes the mean amount, pass 2 flags
// each expense whose absolute deviation from the mean exceeds half the mean,
// then reports the outlier count and the largest deviation.

@pure
fn absReal(x: Real) -> Real {
    if x < 0.0 { ret 0.0 - x; }
    ret x;
}

type Stats {
    outliers: Int;
    maxDev: Real;

    fn note(dev: Real, isOut: Bool) -> Void {
        if isOut { self.outliers = self.outliers + 1; }
        if dev > self.maxDev { self.maxDev = dev; }
        ret;
    }
}

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("expenses_hard_a.json");
    let root: ToonNode = toon_root(doc);
    let items: ToonNode = toon_key(root, "expenses");
    let n: Int = toon_len(items);

    let total: Int = 0;
    loop i in 0..n {
        let e: ToonNode = toon_at(items, i);
        total = total + toon_get_int_or(e, "amount", 0);
    }

    let mean: Real = 0.0;
    if n > 0 { mean = total * 1.0 / n; }
    let threshold: Real = mean * 0.5;

    let stats: Stats = new Stats();

    loop i in 0..n {
        let e: ToonNode = toon_at(items, i);
        let name: Text = toon_get_text_or(e, "name", "UNKNOWN");
        let amount: Int = toon_get_int_or(e, "amount", 0);
        let dev: Real = absReal(amount * 1.0 - mean);
        let isOut: Bool = false;
        if dev > threshold { isOut = true; }
        stats.note(dev, isOut);
        fx { println("expense ", i, ": ", name, " / ", amount, " / dev ", dev:0:2, " / ", isOut); }
    }

    fx {
        println("count = ", n);
        println("mean = ", mean:0:2);
        println("outliers = ", stats.outliers);
        println("maxDev = ", stats.maxDev:0:2);
    }

    toon_close(doc);
    ret;
}

// hard_b_log_levels
// Group a TOON array of log events by level (info/warn/error), report per-level
// counts, the single most frequent level (argmax over the three buckets), and
// the index of the first error event.

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("events_hard_b.json");
    let root: ToonNode = toon_root(doc);
    let events: ToonNode = toon_key(root, "events");
    let n: Int = toon_len(events);

    let info: Int = 0;
    let warn: Int = 0;
    let error: Int = 0;
    let firstError: Int = -1;

    loop i in 0..n {
        let ev: ToonNode = toon_at(events, i);
        let level: Text = toon_get_text_or(ev, "level", "info");
        let msg: Text = toon_get_text_or(ev, "msg", "");
        if level == "info" { info = info + 1; }
        if level == "warn" { warn = warn + 1; }
        if level == "error" {
            error = error + 1;
            if firstError < 0 { firstError = i; }
        }
        fx { println("event ", i, ": ", level, " / ", msg); }
    }

    let dom: Text = "info";
    let domCount: Int = info;
    if warn > domCount { dom = "warn"; domCount = warn; }
    if error > domCount { dom = "error"; domCount = error; }

    fx {
        println("info = ", info);
        println("warn = ", warn);
        println("error = ", error);
        println("dominant = ", dom);
    }
    if firstError < 0 { fx { println("first error: none"); } }
    if firstError >= 0 { fx { println("first error at index ", firstError); } }

    toon_close(doc);
    ret;
}

// hard_c_account_ledger
// Stateful sequential simulation: process a TOON array of operations against an
// account. Deposits add then clamp to a cap; withdrawals succeed only if funds
// suffice (else rejected, balance unchanged); interest applies a percentage.
// Tracks running balance and applied/rejected counts, with a per-op trace.

type Account {
    balance: Int;
    applied: Int;
    rejected: Int;

    fn deposit(amount: Int, cap: Int) -> Void {
        self.balance = self.balance + amount;
        if self.balance > cap { self.balance = cap; }
        self.applied = self.applied + 1;
        ret;
    }

    fn withdraw(amount: Int) -> Bool {
        if amount > self.balance {
            self.rejected = self.rejected + 1;
            ret false;
        }
        self.balance = self.balance - amount;
        self.applied = self.applied + 1;
        ret true;
    }

    fn interest(pct: Int) -> Void {
        let gain: Int = self.balance * pct / 100;
        self.balance = self.balance + gain;
        self.applied = self.applied + 1;
        ret;
    }
}

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("ops_hard_c.json");
    let root: ToonNode = toon_root(doc);
    let ops: ToonNode = toon_key(root, "operations");
    let cap: Int = toon_get_int_or(root, "cap", 1000000);

    let acct: Account = new Account();

    loop i in 0..toon_len(ops) {
        let op: ToonNode = toon_at(ops, i);
        let kind: Text = toon_get_text_or(op, "kind", "");
        let amount: Int = toon_get_int_or(op, "amount", 0);

        if kind == "deposit" {
            acct.deposit(amount, cap);
            fx { println("op ", i, ": deposit ", amount, " -> ", acct.balance); }
        }
        if kind == "withdraw" {
            let ok: Bool = acct.withdraw(amount);
            if ok { fx { println("op ", i, ": withdraw ", amount, " -> ", acct.balance); } }
            if !ok { fx { println("op ", i, ": withdraw ", amount, " REJECTED (balance ", acct.balance, ")"); } }
        }
        if kind == "interest" {
            acct.interest(amount);
            fx { println("op ", i, ": interest ", amount, "% -> ", acct.balance); }
        }
    }

    fx {
        println("final balance = ", acct.balance);
        println("applied = ", acct.applied);
        println("rejected = ", acct.rejected);
    }

    toon_close(doc);
    ret;
}

// hard_d_collatz
// For each number in a TOON array, compute its Collatz stopping time with a
// recursive helper (which itself calls an isEven helper), then report each and
// the maximum stopping time together with the number that produced it.

@pure
fn isEven(n: Int) -> Bool {
    let half: Int = n / 2;
    if half * 2 == n { ret true; }
    ret false;
}

fn collatz(n: Int) -> Int {
    if n <= 1 { ret 0; }
    if isEven(n) { ret 1 + collatz(n / 2); }
    ret 1 + collatz(3 * n + 1);
}

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("numbers_hard_d.json");
    let root: ToonNode = toon_root(doc);
    let nums: ToonNode = toon_key(root, "numbers");
    let n: Int = toon_len(nums);

    let maxSteps: Int = -1;
    let maxNum: Int = 0;

    loop i in 0..n {
        let elem: ToonNode = toon_at(nums, i);
        let num: Int = toon_get_int_or(elem, "n", 0);
        let steps: Int = collatz(num);
        if steps > maxSteps { maxSteps = steps; maxNum = num; }
        fx { println("number ", i, ": ", num, " -> ", steps, " steps"); }
    }

    fx { println("max steps = ", maxSteps, " (number ", maxNum, ")"); }

    toon_close(doc);
    ret;
}

// hard_e_payroll
// Nested TOON traversal: each department holds an array of members. For every
// department report its member count and payroll sum, then the grand totals and
// the department with the highest payroll (argmax over departments).

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("org_hard_e.json");
    let root: ToonNode = toon_root(doc);
    let depts: ToonNode = toon_key(root, "departments");

    let totalMembers: Int = 0;
    let totalPayroll: Int = 0;
    let topPayroll: Int = -1;
    let topName: Text = "none";

    loop d in 0..toon_len(depts) {
        let dept: ToonNode = toon_at(depts, d);
        let name: Text = toon_get_text_or(dept, "name", "UNKNOWN");
        let members: ToonNode = toon_key(dept, "members");
        let count: Int = toon_len(members);

        let payroll: Int = 0;
        loop m in 0..count {
            let person: ToonNode = toon_at(members, m);
            payroll = payroll + toon_get_int_or(person, "salary", 0);
        }

        totalMembers = totalMembers + count;
        totalPayroll = totalPayroll + payroll;
        if payroll > topPayroll { topPayroll = payroll; topName = name; }

        fx { println("dept ", d, ": ", name, " / ", count, " members / payroll ", payroll); }
    }

    fx {
        println("total members = ", totalMembers);
        println("total payroll = ", totalPayroll);
        println("top department = ", topName, " (", topPayroll, ")");
    }

    toon_close(doc);
    ret;
}

// hard_f_sensor_streak
// Adjacent-record analysis over a TOON array of readings: print each step's
// delta to the previous reading, and report the largest single-step increase
// and the length of the longest non-decreasing run.

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("readings_hard_f.json");
    let root: ToonNode = toon_root(doc);
    let readings: ToonNode = toon_key(root, "readings");
    let n: Int = toon_len(readings);

    let prev: Int = 0;
    let havePrev: Bool = false;
    let maxJump: Int = 0;
    let run: Int = 1;
    let bestRun: Int = 1;

    loop i in 0..n {
        let r: ToonNode = toon_at(readings, i);
        let v: Int = toon_get_int_or(r, "value", 0);
        if havePrev {
            let jump: Int = v - prev;
            if jump > maxJump { maxJump = jump; }
            if v >= prev { run = run + 1; }
            if v < prev { run = 1; }
            if run > bestRun { bestRun = run; }
            fx { println("step ", i, ": ", prev, " -> ", v, " (", jump, ")"); }
        }
        prev = v;
        havePrev = true;
    }

    fx {
        println("maxJump = ", maxJump);
        println("longest non-decreasing run = ", bestRun);
    }

    toon_close(doc);
    ret;
}

// hard_g_turnstile
// Drive a two-state turnstile FSM (locked/unlocked) from a TOON array of events
// (coin/push), printing each transition's outcome and reporting the number of
// successful passes and denied pushes plus the final state. The current state is
// snapshotted per event so a transition does not cascade into the other branch.

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("events_hard_g.json");
    let root: ToonNode = toon_root(doc);
    let events: ToonNode = toon_key(root, "events");

    let state: Text = "locked";
    let passes: Int = 0;
    let denied: Int = 0;

    loop i in 0..toon_len(events) {
        let ev: ToonNode = toon_at(events, i);
        let e: Text = toon_get_text_or(ev, "e", "");
        let cur: Text = state;

        if cur == "locked" {
            if e == "coin" { state = "unlocked"; fx { println("event ", i, ": coin -> unlocked"); } }
            if e == "push" { denied = denied + 1; fx { println("event ", i, ": push -> DENIED"); } }
        }
        if cur == "unlocked" {
            if e == "coin" { fx { println("event ", i, ": coin -> thanks"); } }
            if e == "push" { state = "locked"; passes = passes + 1; fx { println("event ", i, ": push -> PASS"); } }
        }
    }

    fx {
        println("passes = ", passes);
        println("denied = ", denied);
        println("final state = ", state);
    }

    toon_close(doc);
    ret;
}

// hard_h_word_lengths
// Classify each word in a TOON array by length (short <4, medium 4-7, long >7),
// summing total characters and tracking the single longest word (argmax over
// string_len, returning the word itself, not just its length).

fn main() -> Void {
    if !has_toon() { fx { println("yyjson unavailable"); } ret; }

    let doc: ToonDoc = toon_parse_file("words_hard_h.json");
    let root: ToonNode = toon_root(doc);
    let words: ToonNode = toon_key(root, "words");

    let shortN: Int = 0;
    let medN: Int = 0;
    let longN: Int = 0;
    let totalChars: Int = 0;
    let maxLen: Int = -1;
    let longest: Text = "none";

    loop i in 0..toon_len(words) {
        let wn: ToonNode = toon_at(words, i);
        let w: Text = toon_get_text_or(wn, "w", "");
        let wlen: Int = string_len(w);
        totalChars = totalChars + wlen;
        let kind: Text = "medium";
        if wlen < 4 { kind = "short"; }
        if wlen > 7 { kind = "long"; }
        if kind == "short" { shortN = shortN + 1; }
        if kind == "medium" { medN = medN + 1; }
        if kind == "long" { longN = longN + 1; }
        if wlen > maxLen { maxLen = wlen; longest = w; }
        fx { println("word ", i, ": ", w, " (", wlen, ") ", kind); }
    }

    fx {
        println("short = ", shortN);
        println("medium = ", medN);
        println("long = ", longN);
        println("total chars = ", totalChars);
        println("longest = ", longest, " (", maxLen, ")");
    }

    toon_close(doc);
    ret;
}
